from __future__ import annotations


def reconcile_entries(entries):
    totals = {}
    for entry in entries:
        account = entry['account']
        if account not in totals:
            totals[account] = {'debit': 0, 'credit': 0, 'balance': 0}
        direction = entry.get('direction')
        if direction == 'debit':
            totals[account]['debit'] += entry.get('amount', 0)
        elif direction == 'credit':
            totals[account]['credit'] += entry.get('amount', 0)
        else:
            raise ValueError('unknown direction')
        totals[account]['balance'] = totals[account]['credit'] - totals[account]['debit']
    return totals
